import { getWorkerGlobals } from "../internal/global-utils.js";
export async function formatCrmProperties({ properties, objectType, formattingOptions, }) {
    const isSingle = !Array.isArray(properties);
    const propertiesList = isSingle ? [properties] : properties;
    const request = {
        propertiesList,
        objectType,
        formattingOptions,
    };
    const response = await getWorkerGlobals().hsWorkerAPI.formatCrmProperties(request);
    const result = (await response.json());
    return isSingle ? result[0] : result;
}
